CREATE EXTERNAL TABLE IF NOT EXISTS orders (order_id INT, user_id INT, product STRING, amount DOUBLE, order_date STRING) ROW FORMAT DELIMITED FIELDS TERMINATED BY ',' STORED AS TEXTFILE LOCATION '/datasets/' TBLPROPERTIES ('skip.header.line.count'='1');

